/* Bootstrap-ul gtag e mutat aici (nu inline in HTML) ca sa respecte CSP-ul
   strict din vercel.json (script-src nu are 'unsafe-inline'). Scriptul extern
   gtag.js e incarcat din index.html <head> si e permis explicit in CSP. */
window.dataLayer = window.dataLayer || [];
function gtag() { dataLayer.push(arguments); }
gtag("js", new Date());
gtag("config", "G-T7H17JSNZ5");

/* ===================== Mobile menu ===================== */
const menuButton = document.querySelector(".mobile-toggle");
const mainNav = document.querySelector(".main-nav");
if (menuButton && mainNav) {
  menuButton.addEventListener("click", () => {
    const isOpen = mainNav.classList.toggle("is-open");
    menuButton.setAttribute("aria-expanded", String(isOpen));
  });
  mainNav.querySelectorAll("a").forEach((link) => {
    link.addEventListener("click", () => {
      mainNav.classList.remove("is-open");
      menuButton.setAttribute("aria-expanded", "false");
    });
  });
}


/* ===================== Nav dropdowns (Portofolii / Contul meu) ===================== */
function initNavDropdown(wrapperId, btnId) {
  const wrapper = document.getElementById(wrapperId);
  const btn = document.getElementById(btnId);
  if (!wrapper || !btn) return;
  btn.addEventListener("click", (e) => {
    e.stopPropagation();
    const isOpen = wrapper.classList.toggle("is-open");
    btn.setAttribute("aria-expanded", String(isOpen));
  });
  wrapper.querySelectorAll("a").forEach((link) => {
    link.addEventListener("click", () => {
      wrapper.classList.remove("is-open");
      btn.setAttribute("aria-expanded", "false");
    });
  });
  document.addEventListener("click", (e) => {
    if (!wrapper.contains(e.target)) {
      wrapper.classList.remove("is-open");
      btn.setAttribute("aria-expanded", "false");
    }
  });
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
      wrapper.classList.remove("is-open");
      btn.setAttribute("aria-expanded", "false");
    }
  });
}
initNavDropdown("portfoliosDropdown", "portfoliosBtn");
initNavDropdown("accountDropdown", "memberButton");

/* ===================== FAQ accordion ===================== */
document.querySelectorAll(".faq-question").forEach((btn) => {
  btn.addEventListener("click", () => {
    const item = btn.closest(".faq-item");
    const answer = item.querySelector(".faq-answer");
    const isOpen = item.classList.toggle("is-open");
    btn.setAttribute("aria-expanded", String(isOpen));
    answer.style.maxHeight = isOpen ? answer.scrollHeight + "px" : "0px";
  });
});

