        checklistTitle: "Практические правила ведения дневника",
        check1: "☐ Заполняй дневник сразу, а не через несколько дней", check2: "☐ Записывай все сделки, включая импульсивные", check3: "☐ Не меняй причину входа после того, как узнал результат", check4: "☐ Прикрепляй скриншоты до и после сделки", check5: "☐ Отделяй стратегию от исполнения", check6: "☐ Оценивай дисциплину, а не только прибыль", check7: "☐ Не меняй стратегию после нескольких убытков", check8: "☐ Анализируй еженедельно и ежемесячно", check9: "☐ Выбирай одно главное улучшение на следующую неделю", check10: "☐ Веди дневник просто, но последовательно",
        checklist2Title: "Чек-лист перед сохранением сделки",
        save1: "☐ Я записал контекст?", save2: "☐ Я объяснил причину входа?", save3: "☐ Я указал риск?", save4: "☐ Я прикрепил начальный скриншот?", save5: "☐ Я отметил эмоции?", save6: "☐ Я сравнил план с исполнением?", save7: "☐ Я рассчитал результат в R?", save8: "☐ Я выставил правильную оценку?", save9: "☐ Я записал главный урок?",
        quizTitle: "Мини-тест",
